def category_report(records):
    """Return ``(category, count, subtotal)`` rows, highest subtotal first.

    Ties break alphabetically by category, matching ``top_categories``.
    Empty input returns an empty list.
    """
    counts = {}
    totals = {}
    for r in records:
        category = r["category"]
        counts[category] = counts.get(category, 0) + 1
        totals[category] = totals.get(category, 0.0) + r["duration"]
    return sorted(
        ((category, counts[category], totals[category]) for category in totals),
        key=lambda row: (-row[2], row[0]),
    )


